import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import { useNavigate } from 'react-router-dom';
import './ProductCard.css';

export default function ProductCard({ product, index = 0 }) {
    const { user } = useAuth();
    const { add } = useCart();
    const navigate = useNavigate();
    const [adding, setAdding] = useState(false);
    const [imgLoaded, setImgLoaded] = useState(false);

    const stars = Array.from({ length: 5 }, (_, i) =>
        i < Math.round(product.rating) ? '★' : '☆'
    ).join('');

    const handleAdd = async(e) => {
        e.stopPropagation();
        if (!user) { navigate('/login'); return; }
        setAdding(true);
        await add(product.id, product.name);
        setTimeout(() => setAdding(false), 800);
    };

    return ( <
        motion.div className = "product-card"
        initial = {
            { opacity: 0, y: 30 } }
        animate = {
            { opacity: 1, y: 0 } }
        transition = {
            { duration: 0.4, delay: index * 0.06, ease: [0.22, 1, 0.36, 1] } }
        whileHover = {
            { y: -6 } } >
        <
        div className = "product-img-wrap" > {!imgLoaded && < div className = "img-skeleton" / > } <
        img src = { product.image }
        alt = { product.name }
        className = { `product-img ${imgLoaded ? 'loaded' : ''}` }
        onLoad = {
            () => setImgLoaded(true) }
        /> <
        div className = "product-overlay" >
        <
        span className = "product-category" > { product.category } < /span> <
        /div> <
        div className = "product-rating-badge" >
        <
        span className = "stars" > { stars } < /span> <
        span > { product.rating } < /span> <
        /div> <
        /div>

        <
        div className = "product-body" >
        <
        h3 className = "product-name" > { product.name } < /h3> <
        p className = "product-desc" > { product.description } < /p> <
        div className = "product-footer" >
        <
        div className = "product-price" >
        <
        span className = "price-label" > $ < /span> <
        span className = "price-value" > { product.price.toFixed(2) } < /span> <
        /div> <
        motion.button className = { `add-btn ${adding ? 'adding' : ''}` }
        onClick = { handleAdd }
        disabled = { adding }
        whileTap = {
            { scale: 0.92 } } >
        {
            adding ? ( <
                motion.span initial = {
                    { scale: 0 } }
                animate = {
                    { scale: 1 } } > ✓ < /motion.span>
            ) : ( <
                >
                <
                svg width = "16"
                height = "16"
                viewBox = "0 0 24 24"
                fill = "none"
                stroke = "currentColor"
                strokeWidth = "2.2" >
                <
                line x1 = "12"
                y1 = "5"
                x2 = "12"
                y2 = "19" / >
                <
                line x1 = "5"
                y1 = "12"
                x2 = "19"
                y2 = "12" / >
                <
                /svg>
                Add <
                />
            )
        } <
        /motion.button> <
        /div> {
            product.stock <= 15 && ( <
                p className = "stock-warning" > ⚡Only { product.stock }
                left < /p>
            )
        } <
        /div> <
        /motion.div>
    );
}
